class Solution:
    def numSubmat(self, mat):
        m, n = len(mat), len(mat[0])
        total = 0
        for top in range(m):
            col_ok = [True] * n
            for bottom in range(top, m):
                run = 0
                for j in range(n):
                    if mat[bottom][j] == 0:
                        col_ok[j] = False
                    if col_ok[j]:
                        run += 1
                    else:
                        run = 0
                    total += run
        return total

