var numSubmat = function(mat) {
    const m = mat.length, n = mat[0].length;
    const heights = new Array(n).fill(0);
    let result = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            heights[j] = mat[i][j] === 1 ? heights[j] + 1 : 0;
        }
        const stack = [];
        let f = 0;
        let rowTotal = 0;
        for (let j = 0; j < n; j++) {
            const h = heights[j];
            let count = 1;
            let removed = 0;
            while (stack.length && stack[stack.length - 1][0] >= h) {
                const [oldH, oldC] = stack.pop();
                removed += oldH * oldC;
                count += oldC;
            }
            stack.push([h, count]);
            f = f - removed + h * count;
            rowTotal += f;
        }
        result += rowTotal;
    }
    return result;
};
